//! Conformance suite for `ferrotorch-distributed` — Layer 3.
//!
//! Tracking issue: #882 (ferrotorch-distributed conformance suite).
//!
//! Reference library: `torch.distributed` (collective ops, process groups),
//! pinned to `torch == 2.11.0`. Fixtures live in
//! `tests/conformance/fixtures.json`, generated by
//! `scripts/regenerate_distributed_fixtures.py`.
//!
//! ## Scope
//!
//! Every public item in `ferrotorch-distributed` falls into one of three groups:
//!
//! 1. **Single-process testable** — items that have a meaningful identity /
//!    error path with `world_size=1`, or items whose structural contracts
//!    (construction, field access, Display) do not require live network I/O:
//!    `is_gloo_available`, `is_mpi_available`, `is_ucc_available`,
//!    `SimulatedBackend::create_group`, `ReduceOp`, `allreduce` (identity),
//!    `broadcast` (identity), `all_gather` (identity), `reduce_scatter`
//!    (identity), `barrier`, `DeviceMesh`, `Placement`, `DTensor`,
//!    `SubBackend`, `DistributedError` Display, `TensorShardSpec`,
//!    `ShardMetadata`, `flat_shard_metadata`.
//!
//! 2. **Multi-process via SimulatedBackend** — items that require >= 2 ranks
//!    but can be exercised in-process using channel-based `SimulatedBackend`:
//!    `allreduce` (multi-rank), `broadcast` (multi-rank), `all_gather`
//!    (multi-rank), `reduce_scatter` (multi-rank), `send`/`recv`,
//!    `sendrecv`, `async_all_gather`, `async_reduce_scatter`.
//!
//! 3. **cascade_skip — genuinely multi-process** — items requiring real
//!    transport (TCP, NCCL, Gloo, MPI, UCC) or multi-process training loops.
//!    These are skipped with a diagnostic and tracking issue reference.
//!    See `_surface_exclusions.toml` for the full exclusion list.
//!
//! ## cascade_skip convention
//!
//! `cascade_skip!(label)` prints a diagnostic and returns early. It is NOT
//! `#[ignore]` — the test still runs and emits the notice. This matches the
//! ferrotorch-mps and ferrotorch-train conformance pattern (no silent skips).

#![allow(
    clippy::cast_possible_truncation,
    clippy::cast_precision_loss,
    clippy::cast_sign_loss,
    clippy::uninlined_format_args,
    clippy::explicit_iter_loop,
    clippy::redundant_else
)]

use std::collections::HashMap;
use std::path::PathBuf;
use std::sync::Arc;

use ferrotorch_core::storage::TensorStorage;
use ferrotorch_core::{FerrotorchError, Tensor};
use ferrotorch_distributed::{
    DEFAULT_COLLECTIVE_TIMEOUT, DeviceMesh, DTensor, DistributedError, Placement, ReduceOp,
    SubBackend,
    all_gather, allreduce, async_all_gather, async_reduce_scatter, barrier, broadcast,
    flat_shard_metadata, is_gloo_available, is_mpi_available, is_ucc_available, recv,
    reduce_scatter, send, sendrecv,
};
use ferrotorch_distributed::backend::{Backend, SimulatedBackend};
use serde::Deserialize;

// ---------------------------------------------------------------------------
// cascade_skip macro
// ---------------------------------------------------------------------------

/// Print a skip diagnostic and return early. Never panics.
macro_rules! cascade_skip {
    ($reason:literal) => {{
        eprintln!("  [cascade_skip] {} — {}", module_path!(), $reason);
        return;
    }};
}

