// ---------------------------------------------------------------------------
// ReduceOp
// ---------------------------------------------------------------------------

/// `ReduceOp` must expose `Sum` and `Mean` variants, matching
/// `torch.distributed.ReduceOp.SUM` / `torch.distributed.ReduceOp.AVG`.
#[test]
fn reduce_op_variants_exist() {
    // Structural check: pattern match exhaustively to ensure no variant was
    // removed from the public enum.
    let sum = ReduceOp::Sum;
    let mean = ReduceOp::Mean;
    match sum {
        ReduceOp::Sum => {}
        ReduceOp::Mean => unreachable!(),
    }
    match mean {
        ReduceOp::Sum => unreachable!(),
        ReduceOp::Mean => {}
    }
    // ReduceOp must implement Debug, Clone, Copy, PartialEq (per public API).
    let _copy = sum;
    assert_eq!(sum, ReduceOp::Sum);
    assert_eq!(mean, ReduceOp::Mean);
    assert_ne!(sum, mean);
}

